import grpc
from concurrent import futures
from envoy.service.auth.v3 import external_auth_pb2_grpc, external_auth_pb2
from google.rpc import code_pb2, status_pb2

class AuthService(external_auth_pb2_grpc.AuthorizationServicer):
    def Check(self, request, context):
        # Extract headers from the incoming request
        headers = {}
        for header in request.attributes.request.http.headers:
            headers[header.key] = header.value

        # Custom authorization logic
        if headers.get('custom-auth-token') == 'valid-token':
            status = status_pb2.Status(code=code_pb2.OK)
        else:
            status = status_pb2.Status(code=code_pb2.PERMISSION_DENIED, message='Authorization failed')

        # Prepare the response
        response = external_auth_pb2.CheckResponse(
            status=status
        )

        return response

